export const regions = [
  { id: "nile-delta", nameKey: "region.nileDelta", emoji: "🌿", color: "#2BBFB3", about: { en: "The Nile Delta is Egypt's fertile heartland, where the Nile fans out into a lush green triangle before meeting the Mediterranean Sea. Home to over 40 million people, it is one of the most densely populated agricultural regions on Earth. Ancient cities like Rosetta and Damietta guard its coastal edges, while inland towns preserve centuries of craft traditions — from palm weaving to furniture making. The delta's wetlands, including Lake Manzala and Lake Burullus, are critical stopovers for millions of migratory birds traveling between Europe and Africa. This is Egypt beyond the pyramids: a world of fishing villages, Ottoman merchant houses, riverside tea gardens, and some of the country's most generous hospitality.", ar: "دلتا النيل هي قلب مصر الخصب، حيث يتفرع النيل إلى مثلث أخضر قبل أن يلتقي بالبحر المتوسط. موطن لأكثر من ٤٠ مليون نسمة، وهي واحدة من أكثر المناطق الزراعية كثافة سكانية على وجه الأرض. مدن قديمة مثل رشيد ودمياط تحرس حوافها الساحلية، بينما تحافظ البلدات الداخلية على قرون من التقاليد الحرفية. الأراضي الرطبة في الدلتا محطات توقف حيوية لملايين الطيور المهاجرة. هذه مصر ما وراء الأهرامات: عالم من قرى الصيد والبيوت التجارية العثمانية وحدائق الشاي النهرية وأكرم ضيافة في البلاد." } },
  { id: "suez-canal", nameKey: "region.suezCanal", emoji: "⚓", color: "#1A7A74", about: { en: "The Suez Canal region is where two continents meet and three seas connect. Since its opening in 1869, this 193-kilometer waterway has been one of the most important shipping lanes in the world, reshaping global trade and the fate of nations. The canal cities — Ismailia, Port Said, and Suez — each developed their own distinct character: Ismailia as the elegant 'Garden City' with its tree-lined boulevards and Lake Timsah; Port Said as a cosmopolitan free port with ornate European Quarter architecture; and Suez as a gateway to the Red Sea. Today, this region offers a unique blend of maritime heritage, colonial architecture, vibrant markets, and waterfront living found nowhere else in Egypt.", ar: "منطقة قناة السويس حيث تلتقي قارتان وتتصل ثلاثة بحار. منذ افتتاحها عام ١٨٦٩، كانت هذه القناة البالغ طولها ١٩٣ كيلومتراً واحدة من أهم ممرات الشحن في العالم. مدن القناة — الإسماعيلية وبورسعيد والسويس — كل منها طورت شخصيتها المميزة: الإسماعيلية كـ'مدينة الحدائق' الأنيقة ببحيرة التمساح؛ وبورسعيد كميناء حر عالمي بعمارة أوروبية مزخرفة؛ والسويس كبوابة للبحر الأحمر. تقدم هذه المنطقة مزيجاً فريداً من التراث البحري والعمارة الاستعمارية والأسواق النابضة والحياة على الواجهة البحرية." } },
  { id: "upper-egypt", nameKey: "region.upperEgypt", emoji: "🏛️", color: "#E8A838", about: { en: "Upper Egypt stretches along the Nile Valley from south of Cairo to the Sudanese border, carrying 5,000 years of continuous civilization along its narrow green ribbon. This is the land of temples and tombs — Luxor's Karnak and Valley of the Kings, Edfu's perfectly preserved Temple of Horus, and Aswan's sun-drenched Nubian villages painted in impossible colors. But beyond the ancient monuments, Upper Egypt is a living culture: farmers work fields using methods little changed since pharaonic times, Nubian families welcome travelers with hibiscus tea and legendary feasts, and artisans keep pottery, weaving, and alabaster-carving traditions alive. The pace of life slows here, governed by the Nile's eternal rhythm.", ar: "يمتد صعيد مصر على طول وادي النيل من جنوب القاهرة إلى الحدود السودانية، حاملاً ٥٠٠٠ عام من الحضارة المتواصلة. هذه أرض المعابد والمقابر — الكرنك في الأقصر ووادي الملوك ومعبد حورس في إدفو والقرى النوبية في أسوان بألوانها المستحيلة. لكن وراء الآثار القديمة، صعيد مصر ثقافة حية: مزارعون يعملون بأساليب لم تتغير كثيراً منذ عصر الفراعنة، وعائلات نوبية ترحب بالمسافرين بالكركديه والولائم الأسطورية، وحرفيون يحافظون على تقاليد الفخار والنسيج ونحت المرمر." } },
  { id: "frontiers", nameKey: "region.frontiers", emoji: "⛰️", color: "#8B5CF6", about: { en: "Egypt's Frontiers encompass the vast, wild landscapes that frame the Nile Valley — from the Western Desert's ancient oases to the Red Sea's coral wonderlands and Sinai's rugged mountains. Siwa Oasis, near the Libyan border, preserves Berber language and traditions unchanged for millennia, its mud-brick fortress rising above salt lakes and date palm groves. Along the Red Sea coast, Dahab offers world-class diving at the Blue Hole and a laid-back Bedouin beach culture. Marsa Alam and Hurghada reveal pristine coral reefs teeming with marine life. These frontier regions represent Egypt at its most adventurous — where desert silence meets underwater spectacle, and ancient cultures thrive far from the tourist trail.", ar: "تشمل حدود مصر المناظر الطبيعية البرية الشاسعة التي تؤطر وادي النيل — من واحات الصحراء الغربية القديمة إلى عجائب الشعاب المرجانية في البحر الأحمر وجبال سيناء الوعرة. واحة سيوة قرب الحدود الليبية تحافظ على اللغة والتقاليد الأمازيغية منذ آلاف السنين. على ساحل البحر الأحمر، تقدم دهب غوصاً عالمياً في الحفرة الزرقاء وثقافة شاطئية بدوية مسترخية. مرسى علم والغردقة تكشف شعاباً مرجانية بكر تعج بالحياة البحرية. هذه المناطق الحدودية تمثل مصر في أكثر حالاتها مغامرة." } },
];

